def generate_self_signed_cert():
    if os.path.exists(PRIVATE_KEY_PATH) and os.path.exists(CERT_PATH):
        return
    
    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=2048,
        backend=default_backend()
    )
    
    with open(PRIVATE_KEY_PATH, 'wb') as f:
        f.write(private_key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.PKCS8,
            encryption_algorithm=serialization.NoEncryption()
        ))
    
    subject = issuer = x509.Name([
        x509.NameAttribute(NameOID.COUNTRY_NAME, "US"),
        x509.NameAttribute(NameOID.STATE_OR_PROVINCE_NAME, "State"),
        x509.NameAttribute(NameOID.LOCALITY_NAME, "City"),
        x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Example IDP"),
        x509.NameAttribute(NameOID.COMMON_NAME, "idp.example.com"),
    ])
    
    cert = x509.CertificateBuilder().subject_name(
        subject
    ).issuer_name(
        issuer
    ).public_key(
        private_key.public_key()
    ).serial_number(
        x509.random_serial_number()
    ).not_valid_before(
        datetime.utcnow()
    ).not_valid_after(
        datetime.utcnow() + timedelta(days=3650)
    ).add_extension(
        x509.SubjectAlternativeName([
            x509.DNSName("idp.example.com"),
        ]),
        critical=False,
    ).sign(private_key, hashes.SHA256(), default_backend())
    
    with open(CERT_PATH, 'wb') as f:
        f.write(cert.public_bytes(serialization.Encoding.PEM))

def load_certificate():
    with open(CERT_PATH, 'rb') as f:
        cert_data = f.read()
    return cert_data.decode('utf-8')

def load_private_key():
    with open(PRIVATE_KEY_PATH, 'rb') as f:
        key_data = f.read()
    return key_data.decode('utf-8')

def create_saml_response(user_attributes, sp_entity_id, acs_url, in_response_to=None):
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    session_not_on_or_after = (datetime.utcnow() + timedelta(hours=8)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    response_id = '_' + str(uuid.uuid4())
    assertion_id = '_' + str(uuid.uuid4())
    
    namespaces = {
        'samlp': 'urn:oasis:names:tc:SAML:2.0:protocol',
        'saml': 'urn:oasis:names:tc:SAML:2.0:assertion',
        'ds': 'http://www.w3.org/2000/09/xmldsig#'
    }
    
    for prefix, uri in namespaces.items():
        etree.register_namespace(prefix, uri)
    
    response = etree.Element(
        '{urn:oasis:names:tc:SAML:2.0:protocol}Response',
        ID=response_id,
        Version='2.0',
        IssueInstant=issue_instant,
        Destination=acs_url,
        nsmap=namespaces
    )
    
    if in_response_to:
        response.set('InResponseTo', in_response_to)
    
    issuer = etree.SubElement(response, '{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
    issuer.text = IDP_ENTITY_ID
    
    status = etree.SubElement(response, '{urn:oasis:names:tc:SAML:2.0:protocol}Status')
    status_code = etree.SubElement(status, '{urn:oasis:names:tc:SAML:2.0:protocol}StatusCode')
    status_code.set('Value', 'urn:oasis:names:tc:SAML:2.0:status:Success')
    
    assertion = etree.SubElement(response, '{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    assertion.set('ID', assertion_id)
    assertion.set('Version', '2.0')
    assertion.set('IssueInstant', issue_instant)
    
    assertion_issuer = etree.SubElement(assertion, '{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
    assertion_issuer.text = IDP_ENTITY_ID
    
    subject = etree.SubElement(assertion, '{urn:oasis:names:tc:SAML:2.0:assertion}Subject')
    name_id = etree.SubElement(subject, '{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
    name_id.set('Format', 'urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress')
    name_id.text = user_attributes.get('email', '')
    
    subject_confirmation = etree.SubElement(subject, '{urn:oasis:names:tc:SAML:2.0:assertion}SubjectConfirmation')
    subject_confirmation.set('Method', 'urn:oasis:names:tc:SAML:2.0:cm:bearer')
    subject_confirmation_data = etree.SubElement(subject_confirmation, '{urn:oasis:names:tc:SAML:2.0:assertion}SubjectConfirmationData')
    subject_confirmation_data.set('NotOnOrAfter', not_on_or_after)
    subject_confirmation_data.set('Recipient', acs_url)
    if in_response_to:
        subject_confirmation_data.set('InResponseTo', in_response_to)
    
    conditions = etree.SubElement(assertion, '{urn:oasis:names:tc:SAML:2.0:assertion}Conditions')
    conditions.set('NotBefore', not_before)
    conditions.set('NotOnOrAfter', not_on_or_after)
    
    audience_restriction = etree.SubElement(conditions, '{urn:oasis:names:tc:SAML:2.0:assertion}AudienceRestriction')
    audience = etree.SubElement(audience_restriction, '{urn:oasis:names:tc:SAML:2.0:assertion}Audience')
    audience.text = sp_entity_id
    
    authn_statement = etree.SubElement(assertion, '{urn:oasis:names:tc:SAML:2.0:assertion}AuthnStatement')
    authn_statement.set('AuthnInstant', issue_instant)
    authn_statement.set('SessionNotOnOrAfter', session_not_on_or_after)
    authn_statement.set('SessionIndex', assertion_id)
    
    authn_context = etree.SubElement(authn_statement, '{urn:oasis:names:tc:SAML:2.0:assertion}AuthnContext')
    authn_context_class_ref = etree.SubElement(authn_context, '{urn:oasis:names:tc:SAML:2.0:assertion}AuthnContextClassRef')
    authn_context_class_ref.text = 'urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'
    
    attribute_statement = etree.SubElement(assertion, '{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement')
    
    for attr_name, attr_value in user_attributes.items():
        attribute = etree.SubElement(attribute_statement, '{urn:oasis:names:tc:SAML:2.0:assertion}Attribute')
        attribute.set('Name', attr_name)
        attribute.set('NameFormat', 'urn:oasis:names:tc:SAML:2.0:attrname-format:basic')
        
        attribute_value = etree.SubElement(attribute, '{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')
        attribute_value.set('{http://www.w3.org/2001/XMLSchema-instance}type', 'xs:string')
        attribute_value.text = str(attr_value)
    
    private_key = load_private_key()
    cert = load_certificate()
    
    signer = XMLSigner(
        method=signxml.methods.enveloped,
        signature_algorithm='rsa-sha256',
        digest_algorithm='sha256',
        c14n_algorithm='http://www.w3.org/2001/10/xml-exc-c14n#'
    )
    
    signed_assertion = signer.sign(
        assertion,
        key=private_key,
        cert=cert
    )
    
    response.replace(assertion, signed_assertion)
    
    xml_string = etree.tostring(response, encoding='unicode', pretty_print=False)
    
    return base64.b64encode(xml_string.encode('utf-8')).decode('utf-8')

