@app.route('/saml/sso', methods=['GET', 'POST'])
def sso():
    if request.method == 'GET':
        saml_request = request.args.get('SAMLRequest', '')
        relay_state = request.args.get('RelayState', '')
        
        return render_template_string(LOGIN_FORM, 
                                     saml_request=saml_request, 
                                     relay_state=relay_state,
                                     error=None)
    
    elif request.method == 'POST':
        username = request.form.get('username', '')
        password = request.form.get('password', '')
        saml_request = request.form.get('SAMLRequest', '')
        relay_state = request.form.get('RelayState', '')
        
        if username not in USER_DATABASE or USER_DATABASE[username]['password'] != password:
            return render_template_string(LOGIN_FORM, 
                                         saml_request=saml_request, 
                                         relay_state=relay_state,
                                         error='Invalid username or password')
        
        user_attributes = USER_DATABASE[username]['attributes']
        
        sp_entity_id = None
        acs_url = None
        in_response_to = None
        
        if saml_request:
            try:
                decoded_request = base64.b64decode(saml_request)
                import zlib
                try:
                    inflated_request = zlib.decompress(decoded_request, -15)
                except:
                    inflated_request = decoded_request
                
                root = etree.fromstring(inflated_request)
                in_response_to = root.get('ID')
                acs_url = root.get('AssertionConsumerServiceURL')
                
                issuer_elem = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Issuer')
                if issuer_elem is not None:
                    sp_entity_id = issuer_elem.text
            except Exception as e:
                pass
        
        if not sp_entity_id or sp_entity_id not in SP_REGISTRY:
            sp_entity_id = list(SP_REGISTRY.keys())[0]
        
        sp_config = SP_REGISTRY[sp_entity_id]
        if not acs_url:
            acs_url = sp_config['acs_url']
        
        saml_response = create_saml_response(
            user_attributes=user_attributes,
            sp_entity_id=sp_entity_id,
            acs_url=acs_url,
            in_response_to=in_response_to
        )
        
        return render_template_string(SAML_POST_FORM,
                                     acs_url=acs_url,
                                     saml_response=saml_response,
                                     relay_state=relay_state)

